const body = $json.body || $json;
const entry = body.entry;
if (!entry || !entry[0] || !entry[0].changes || !entry[0].changes[0]) return [];
const value = entry[0].changes[0].value;
if (value.statuses && !value.messages) return [];
if (!value.messages || !value.messages[0]) return [];
const message = value.messages[0];
const messageId = message.id;
const from = message.from;
const type = message.type;
let text = '';
if (type === 'text' && message.text) {
  text = message.text.body || '';
} else if (type === 'audio') {
  text = '[AUDIO]';
} else if (type === 'image') {
  text = '[IMAGE]';
} else {
  text = '[OTHER]';
}
return [{ json: { messageId, from, type, text } }];

const originalFrom = $('Extract Message').first().json.from;
const originalText = $('Extract Message').first().json.text;
const originalType = $('Extract Message').first().json.type;
const originalMessageId = $('Extract Message').first().json.messageId;

let isDuplicate = false;

if ($json.error || ($json.statusCode && $json.statusCode >= 400)) {
  isDuplicate = false;
} else {
  const result = Array.isArray($json) ? $json : [];
  isDuplicate = result.length === 0;
}

return [{ json: { messageId: originalMessageId, from: originalFrom, type: originalType, text: originalText, isDuplicate } }];

const from = $('Extract Message').first().json.from;
const text = ($('Extract Message').first().json.text || '').trim();
const type = $('Extract Message').first().json.type;
const messageId = $('Extract Message').first().json.messageId;

let session = {};
const sessionResult = Array.isArray($json) ? $json : [];
if (sessionResult.length > 0) {
  session = sessionResult[0];
}

let humanTakeover = session.human_takeover || false;
const pendingAppointment = session.pending_appointment || null;

const textLower = text.toLowerCase();
if (textLower === '#bot') {
  humanTakeover = false;
} else if (textLower === '#humano') {
  humanTakeover = true;
}

const hasPendingAppointment = pendingAppointment !== null && typeof pendingAppointment === 'object';

return [{ json: {
  from,
  text,
  type,
  messageId,
  isHumanHandling: humanTakeover,
  hasPendingAppointment,
  pendingAppointment: pendingAppointment,
  sessionHumanTakeover: humanTakeover
}}];

const text = ($json.text || '').toLowerCase().trim();
const from = $json.from;
const pending = $json.pendingAppointment;

const confirmWords = ['sim', 's', 'yes', 'confirmar', 'confirmo', 'ok', 'pode', '1', 'claro', 'certo'];
const rejectWords = ['não', 'nao', 'no', 'cancelar', 'cancelo', 'cancela', 'desistir', '2', 'nope'];

const isConfirmed = confirmWords.some(w => text === w || text.startsWith(w + ' ') || text.includes(w));
const isRejected = rejectWords.some(w => text === w || text.startsWith(w + ' ') || text.includes(w));

if (isConfirmed) {
  return [{ json: {
    pendingAction: 'confirmed',
    from,
    nome: pending.nome,
    especialidade: pending.especialidade,
    data: pending.data,
    hora: pending.hora,
    text: $json.text
  }}];
}

if (isRejected) {
  return [{ json: {
    pendingAction: 'rejected',
    from,
    nome: pending.nome,
    text: $json.text
  }}];
}

return [{ json: {
  pendingAction: 'unclear',
  from,
  nome: pending.nome,
  especialidade: pending.especialidade,
  data: pending.data,
  hora: pending.hora,
  text: $json.text,
  mensagem: `Por favor, responda *SIM* para confirmar ou *NÃO* para cancelar o agendamento:\n\n👤 ${pending.nome}\n🏥 ${pending.especialidade}\n📅 ${pending.data}\n⏰ ${pending.hora}`
}}];

const from = $input.first().json.from;

if ($json.error) {
  return [{ json: { intencao: 'erro_ia', mensagem: 'Desculpe, estamos com dificuldades técnicas. Por favor, tente novamente em instantes. 🙏', from } }];
}

let raw = '';
try {
  raw = $json.choices[0].message.content || '';
} catch(e) {
  return [{ json: { intencao: 'erro_ia', mensagem: 'Não consegui processar sua mensagem. Tente novamente.', from } }];
}

// Limpar markdown
raw = raw.replace(/```json\n?/gi, '').replace(/```\n?/g, '').trim();

// Extrair JSON do texto (a IA pode responder com texto + JSON)
const jsonMatch = raw.match(/\{[\s\S]*\}/);
if (jsonMatch) {
  raw = jsonMatch[0];
}

let parsed;
try {
  parsed = JSON.parse(raw);
} catch(e) {
  const intencaoMatch = raw.match(/"intencao"\s*:\s*"([^"]+)"/);
  const mensagemMatch = raw.match(/"mensagem"\s*:\s*"([^"]+)"/);
  return [{ json: {
    intencao: intencaoMatch ? intencaoMatch[1] : 'outro',
    mensagem: mensagemMatch ? mensagemMatch[1] : 'Como posso ajudá-lo?',
    from
  }}];
}

parsed.from = parsed.from || from;
parsed.intencao = (parsed.intencao || 'outro').toLowerCase().trim();
parsed.nome = parsed.nome || null;
parsed.especialidade = parsed.especialidade || null;
parsed.mensagem = parsed.mensagem || 'Como posso ajudá-lo?';

// ✅ Validar e normalizar data — aceita DD/MM/AAAA
if (parsed.data) {
  if (/^\d{2}\/\d{2}\/\d{4}$/.test(parsed.data)) {
    // Formato correcto — mantém como está
    parsed.data = parsed.data;
  } else if (/^\d{4}-\d{2}-\d{2}$/.test(parsed.data)) {
    // Converter YYYY-MM-DD → DD/MM/AAAA (segurança caso a IA falhe)
    const [ano, mes, dia] = parsed.data.split('-');
    parsed.data = `${dia}/${mes}/${ano}`;
  } else {
    // Formato inválido — anula e deixa o Validate tratar
    parsed.data = null;
  }
}

// ✅ Validar hora — forçar HH:MM
if (parsed.hora) {
  const horaMatch = parsed.hora.match(/^(\d{1,2}):(\d{2})$/);
  if (horaMatch) {
    const hh = String(horaMatch[1]).padStart(2, '0');
    const mm = horaMatch[2];
    parsed.hora = `${hh}:${mm}`;
  } else {
    parsed.hora = null;
  }
}

return [{ json: parsed }];

const data = $json.data;
const hora = $json.hora;
const nome = $json.nome;
const especialidade = $json.especialidade;
const from = $json.from;

const missing = [];
if (!nome) missing.push('seu nome completo');
if (!especialidade) missing.push('a especialidade desejada (ex: Clínico Geral, Cardiologista)');
if (!data) missing.push('a data desejada (ex: 25/03/2025)');
if (!hora) missing.push('o horário desejado (ex: 14:30)');

if (missing.length > 0) {
  return [{ json: { 
    valid: false, from, nome, 
    mensagem: `Para agendar sua consulta, ainda preciso de: ${missing.join(', ')}. Por favor, informe esses dados. 😊` 
  }}];
}

// 🕐 Validar horário
const [hh, mm] = hora.split(':').map(Number);
const totalMinutes = hh * 60 + (mm || 0);

if (isNaN(hh) || isNaN(mm) || totalMinutes < 8 * 60 || totalMinutes > 18 * 60) {
  return [{ json: {
    valid: false, from, nome,
    mensagem: '🕐 Nosso horário de atendimento é das *08:00 às 18:00* (hora de Luanda).\n\nPor favor, escolha um horário dentro desse intervalo.'
  }}];
}

// 📅 Validar formato correto (DD/MM/AAAA)
if (!/^\d{2}\/\d{2}\/\d{4}$/.test(data)) {
  return [{ json: {
    valid: false, from, nome,
    mensagem: '📅 Formato de data inválido. Use DD/MM/AAAA (ex: 25/03/2025).'
  }}];
}

// 🔄 Converter para YYYY-MM-DD
const [dia, mes, ano] = data.split('/');
const dataFormatada = `${ano}-${mes}-${dia}`;

// 🕒 Data atual em Luanda
const LUANDA_OFFSET_MS = 60 * 60 * 1000;
const nowUTC = Date.now();
const nowLuanda = new Date(nowUTC + LUANDA_OFFSET_MS);
const todayLuanda = nowLuanda.toISOString().split('T')[0];

// 🚫 Comparar corretamente
if (dataFormatada < todayLuanda) {
  return [{ json: {
    valid: false, from, nome,
    mensagem: '📅 A data informada já passou. Por favor, escolha uma data futura.'
  }}];
}

// ✅ Tudo certo
return [{ json: { 
  valid: true, 
  from, 
  nome, 
  especialidade, 
  data: dataFormatada, // padronizado
  hora, 
  mensagem: $json.mensagem, 
  intencao: $json.intencao 
}}];

